import React, { useState, useEffect } from 'react';

const EMPTY_FTP = { ftp_host: '', ftp_port: '', ftp_user: '', ftp_pass: '', ftp_directory: '' };
const EMPTY_FORM = {
  station_code: '', station_name: '', station_address: '',
  phone_number: '', recharge_date: '', ftp_list: [{ ...EMPTY_FTP }],
};

const s = {
  overlay: {
    position: 'fixed', inset: 0, background: 'rgba(10,25,44,0.6)',
    display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
    zIndex: 7000, overflowY: 'auto', padding: '24px 16px',
  },
  modal: {
    background: '#fff', borderRadius: 16, width: '100%', maxWidth: 720,
    boxShadow: '0 8px 48px rgba(0,0,0,0.22)', marginTop: 'auto', marginBottom: 'auto',
  },
  header: {
    padding: '20px 28px 16px', borderBottom: '1px solid #ccd8e8',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
  },
  title: { fontSize: 17, fontWeight: 700, color: '#0d3b6e' },
  body: { padding: '24px 28px' },
  section: { marginBottom: 24 },
  sectionTitle: {
    fontSize: 12, fontWeight: 700, color: '#7a94a8', letterSpacing: '0.08em',
    textTransform: 'uppercase', marginBottom: 14,
  },
  grid2: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px 16px' },
  grid1: { display: 'grid', gridTemplateColumns: '1fr', gap: 14 },
  field: { display: 'flex', flexDirection: 'column', gap: 5 },
  label: { fontSize: 12, fontWeight: 600, color: '#3d5a72' },
  input: {
    padding: '9px 12px', borderRadius: 8, border: '1px solid #ccd8e8',
    fontSize: 13, color: '#12263a', outline: 'none', transition: '0.15s',
    background: '#f5f8fc',
  },
  ftpCard: {
    border: '1px solid #ccd8e8', borderRadius: 10, padding: '16px',
    background: '#f5f8fc', marginBottom: 12, position: 'relative',
  },
  ftpTitle: { fontSize: 12, fontWeight: 700, color: '#0d3b6e', marginBottom: 12 },
  removeBtn: {
    position: 'absolute', top: 12, right: 12,
    background: '#fdecea', color: '#b5261e', border: 'none',
    borderRadius: 6, padding: '4px 10px', fontSize: 11, fontWeight: 600,
    cursor: 'pointer',
  },
  addFtpBtn: {
    display: 'flex', alignItems: 'center', gap: 6,
    padding: '8px 14px', borderRadius: 8, border: '1px dashed #a8bdd4',
    background: 'transparent', color: '#1a5fa8', fontSize: 12, fontWeight: 600,
    cursor: 'pointer', transition: '0.15s',
  },
  footer: {
    padding: '16px 28px 24px', display: 'flex',
    justifyContent: 'flex-end', gap: 10, borderTop: '1px solid #ccd8e8',
  },
  btnCancel: {
    padding: '9px 22px', borderRadius: 8, border: '1px solid #ccd8e8',
    background: '#f5f8fc', color: '#3d5a72', fontSize: 13, fontWeight: 600, cursor: 'pointer',
  },
  btnSave: {
    padding: '9px 26px', borderRadius: 8, border: 'none',
    background: '#0d3b6e', color: '#fff', fontSize: 13, fontWeight: 700, cursor: 'pointer',
  },
};

export default function StationForm({ open, station, onClose, onSave }) {
  const [form, setForm] = useState(EMPTY_FORM);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (open) {
      if (station) {
        setForm({
          ...station,
          recharge_date: station.recharge_date ? station.recharge_date.slice(0, 16) : '',
          ftp_list: station.ftp_list?.length ? station.ftp_list : [{ ...EMPTY_FTP }],
        });
      } else {
        setForm({ ...EMPTY_FORM, ftp_list: [{ ...EMPTY_FTP }] });
      }
    }
  }, [open, station]);

  if (!open) return null;

  const set = (key, val) => setForm(f => ({ ...f, [key]: val }));
  const setFtp = (i, key, val) => {
    const list = [...form.ftp_list];
    list[i] = { ...list[i], [key]: val };
    setForm(f => ({ ...f, ftp_list: list }));
  };
  const addFtp = () => setForm(f => ({ ...f, ftp_list: [...f.ftp_list, { ...EMPTY_FTP }] }));
  const removeFtp = (i) => setForm(f => ({ ...f, ftp_list: f.ftp_list.filter((_, idx) => idx !== i) }));

  const handleSubmit = async () => {
    if (!form.station_code || !form.station_name) return alert('Vui lòng nhập Mã và Tên trạm!');
    setLoading(true);
    const payload = {
      ...form,
      recharge_date: form.recharge_date ? new Date(form.recharge_date).toISOString() : null,
      ftp_list: form.ftp_list.map(f => ({ ...f, ftp_port: Number(f.ftp_port) || 21 })),
    };
    await onSave(payload);
    setLoading(false);
  };

  const Field = ({ label, name, value, onChange, type = 'text', grid, required }) => (
    <div style={{ ...s.field, ...(grid ? {} : {}) }}>
      <label style={s.label}>{label}{required && <span style={{ color: '#b5261e' }}> *</span>}</label>
      <input
        type={type} value={value} onChange={e => onChange(e.target.value)}
        style={s.input}
        onFocus={e => e.target.style.borderColor = '#1a5fa8'}
        onBlur={e => e.target.style.borderColor = '#ccd8e8'}
      />
    </div>
  );

  return (
    <div style={s.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={s.modal}>
        <div style={s.header}>
          <span style={s.title}>{station ? '✏️ Chỉnh sửa trạm' : '➕ Thêm trạm mới'}</span>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: 20, cursor: 'pointer', color: '#7a94a8' }}>✕</button>
        </div>

        <div style={s.body}>
          {/* Thông tin trạm */}
          <div style={s.section}>
            <div style={s.sectionTitle}>Thông tin trạm</div>
            <div style={s.grid2}>
              <Field label="Mã trạm" name="station_code" value={form.station_code} onChange={v => set('station_code', v)} required />
              <Field label="Tên trạm" name="station_name" value={form.station_name} onChange={v => set('station_name', v)} required />
              <Field label="Địa chỉ" name="station_address" value={form.station_address} onChange={v => set('station_address', v)} />
              <Field label="Số điện thoại" name="phone_number" value={form.phone_number} onChange={v => set('phone_number', v)} />
            </div>
            <div style={{ marginTop: 14 }}>
              <Field label="Ngày nạp dữ liệu" name="recharge_date" type="datetime-local" value={form.recharge_date} onChange={v => set('recharge_date', v)} />
            </div>
          </div>

          {/* Danh sách FTP */}
          <div style={s.section}>
            <div style={s.sectionTitle}>Danh sách FTP ({form.ftp_list.length})</div>
            {form.ftp_list.map((ftp, i) => (
              <div key={i} style={s.ftpCard}>
                <div style={s.ftpTitle}>FTP Server #{i + 1}</div>
                {form.ftp_list.length > 1 && (
                  <button onClick={() => removeFtp(i)} style={s.removeBtn}>Xoá</button>
                )}
                <div style={s.grid2}>
                  <div style={s.field}>
                    <label style={s.label}>Host</label>
                    <input value={ftp.ftp_host} onChange={e => setFtp(i, 'ftp_host', e.target.value)} style={s.input}
                      onFocus={e => e.target.style.borderColor = '#1a5fa8'} onBlur={e => e.target.style.borderColor = '#ccd8e8'} />
                  </div>
                  <div style={s.field}>
                    <label style={s.label}>Port</label>
                    <input type="number" value={ftp.ftp_port} onChange={e => setFtp(i, 'ftp_port', e.target.value)} style={s.input} placeholder="21"
                      onFocus={e => e.target.style.borderColor = '#1a5fa8'} onBlur={e => e.target.style.borderColor = '#ccd8e8'} />
                  </div>
                  <div style={s.field}>
                    <label style={s.label}>Username</label>
                    <input value={ftp.ftp_user} onChange={e => setFtp(i, 'ftp_user', e.target.value)} style={s.input}
                      onFocus={e => e.target.style.borderColor = '#1a5fa8'} onBlur={e => e.target.style.borderColor = '#ccd8e8'} />
                  </div>
                  <div style={s.field}>
                    <label style={s.label}>Password</label>
                    <input type="password" value={ftp.ftp_pass} onChange={e => setFtp(i, 'ftp_pass', e.target.value)} style={s.input}
                      onFocus={e => e.target.style.borderColor = '#1a5fa8'} onBlur={e => e.target.style.borderColor = '#ccd8e8'} />
                  </div>
                  <div style={{ ...s.field, gridColumn: '1 / -1' }}>
                    <label style={s.label}>Thư mục</label>
                    <input value={ftp.ftp_directory} onChange={e => setFtp(i, 'ftp_directory', e.target.value)} style={{ ...s.input, fontFamily: 'JetBrains Mono, monospace', fontSize: 12 }} placeholder="/data/aws"
                      onFocus={e => e.target.style.borderColor = '#1a5fa8'} onBlur={e => e.target.style.borderColor = '#ccd8e8'} />
                  </div>
                </div>
              </div>
            ))}
            <button onClick={addFtp} style={s.addFtpBtn}>+ Thêm FTP Server</button>
          </div>
        </div>

        <div style={s.footer}>
          <button onClick={onClose} style={s.btnCancel}>Huỷ</button>
          <button onClick={handleSubmit} disabled={loading} style={{ ...s.btnSave, opacity: loading ? 0.7 : 1 }}>
            {loading ? 'Đang lưu...' : station ? 'Cập nhật' : 'Tạo trạm'}
          </button>
        </div>
      </div>
    </div>
  );
}
